.root {
  --level-offset: var(--mantine-spacing-lg);
  --tree-line-width: rem(1px);
  --tree-line-color: var(--mantine-color-default-border);
  margin: 0;
  padding: 0;
  user-select: none;
}

.subtree {
  margin: 0;
  padding: 0;
}

.node {
  cursor: pointer;
  list-style: none;
  margin: 0;
  padding: 0;
  outline: 0;

  &:focus-visible {
    > .label {
      outline: 2px solid var(--mantine-primary-color-filled);
      outline-offset: 2px;
    }
  }
}

.label {
  position: relative;
  padding-inline-start: var(--label-offset);

  &:where([data-selected]) {
    @mixin where-light {
      background-color: var(--mantine-color-gray-1);
    }

    @mixin where-dark {
      background-color: var(--mantine-color-dark-5);
    }
  }

  &:where([data-dragging]) {
    opacity: 0.4;
  }

  &:where([data-drag-over='before'])::before {
    content: '';
    position: absolute;
    top: -1px;
    inset-inline-start: var(--label-offset, 0);
    inset-inline-end: 0;
    height: 2px;
    background-color: var(--mantine-primary-color-filled);
    pointer-events: none;
    z-index: 1;
  }

  &:where([data-drag-over='after'])::after {
    content: '';
    position: absolute;
    bottom: -1px;
    inset-inline-start: var(--label-offset, 0);
    inset-inline-end: 0;
    height: 2px;
    background-color: var(--mantine-primary-color-filled);
    pointer-events: none;
    z-index: 1;
  }

  &:where([data-drag-over='inside']) {
    background-color: var(--mantine-primary-color-light);
  }
}

:where([data-with-lines]) {
  .node {
    position: relative;
  }

  .subtree > .node {
    &::before {
      content: '';
      position: absolute;
      top: rem(12px);
      inset-inline-start: calc(var(--label-offset) - var(--level-offset) / 2);
      width: calc(var(--level-offset) / 2);
      height: 0;
      border-top: var(--tree-line-width) solid var(--tree-line-color);
      pointer-events: none;
    }

    &::after {
      content: '';
      position: absolute;
      top: 0;
      bottom: 0;
      inset-inline-start: calc(var(--label-offset) - var(--level-offset) / 2);
      width: 0;
      border-inline-start: var(--tree-line-width) solid var(--tree-line-color);
      pointer-events: none;
    }

    &:last-child::after {
      bottom: auto;
      height: rem(12px);
    }
  }
}
